import json

class MockApiResponse:
    """
    requests.Response nesnesini taklit eden basitleştirilmiş bir mock sınıfı.
    """
    def __init__(self, status_code, json_data=None, text_content=None, headers=None):
        self.status_code = status_code
        self._json_data = json_data
        self._text_content = text_content
        self.headers = headers if headers is not None else {}

    def json(self):
        """
        Yanıtın JSON içeriğini Python sözlüğüne dönüştürür.
        """
        if self._json_data is None:
            raise ValueError("Bu yanıt için JSON veri mevcut değil.")
        return self._json_data

    @property
    def text(self):
        """
        Yanıtın ham metin içeriğini döndürür.
        """
        if self._text_content is not None:
            return self._text_content
        elif self._json_data is not None:
            return json.dumps(self._json_data)
        return ""

def mock_eden_test_api_response(
    status_code=200,
    json_data=None,
    headers=None,
    raw_text=None
):
    """
    Belirli bir API'den (örneğin 'eden test' hizmeti) gelen bir HTTP yanıtını taklit eder.

    Parametreler:
        status_code (int): HTTP durum kodu (varsayılan 200).
        json_data (dict, optional): Yanıt gövdesinin JSON verisi. Sağlanmazsa varsayılan bir veri oluşturulur.
        headers (dict, optional): Yanıt başlıkları. Sağlanmazsa varsayılan başlıklar ayarlanır.
        raw_text (str, optional): Yanıtın ham metin içeriği. Sağlanırsa 'json_data' yerine bunun `.text` özelliği olarak kullanılır.

    Dönüş:
        MockApiResponse: requests.Response nesnesini taklit eden bir mock nesnesi.
    """
    if json_data is None and raw_text is None:
        # Varsayılan başarılı yanıt verisi
        json_data = {
            "success": True,
            "message": "Eden Test API çağrısı başarılı.",
            "data": {
                "test_id": "eden_test_mock_123",
                "status": "completed",
                "details": "Bu bir mock yanıtıdır."
            }
        }
    elif json_data is None and raw_text is not None:
        # raw_text varsa ve json_data yoksa, json_data'yı null bırak
        # böylece .json() çağrısı ValueError fırlatır
        pass

    if headers is None and json_data is not None:
        headers = {"Content-Type": "application/json"}
    elif headers is None:
        headers = {} # json_data yoksa boş başlıklar

    return MockApiResponse(
        status_code=status_code,
        json_data=json_data,
        text_content=raw_text,
        headers=headers
    )
